            num_output_compressed_accounts: num_accounts as u8,
            num_new_addresses: 0,
            compress: 0,
            fee_config,
        }),
    )
    .await
    .unwrap()
    .unwrap();
    // Assertion.
    {
        let mut test_indexer = rpc.clone_indexer()?;
        let slot: u64 = rpc.get_slot().await.unwrap();
        let (created_compressed_accounts, _) =
