        let fee_payer_balance = self
            .rpc
            .get_balance(&self.rpc.get_payer().pubkey())
            .await
            .unwrap();
        perform_address_merkle_tree_roll_over_forester(
            payer,
            &mut self.rpc,
            &new_nullifier_queue_keypair,
            &new_merkle_tree_keypair,
            &bundle.merkle_tree,
            &bundle.queue,
